  .lsystem-card label,
  .lsystem-output { color: var(--muted); }

  .lsystem-grid {
    display: grid;
    grid-template-columns: minmax(17rem, 24rem) minmax(0, 1fr);
    gap: 1rem;
  }

  .lsystem-card {
    border: 1px solid var(--line);
    padding: 1rem;
    display: grid;
    gap: .75rem;
    align-content: start;
  }

  .lsystem-wide { min-width: 0; }

  .lsystem-card h2 {
    font-size: 1rem;
    margin: 0;
  }

  .lsystem-card label {
    display: grid;
    gap: .25rem;
  }

