import PageLayout from '../layouts/PageLayout.astro';
---

<PageLayout name="braid group composer" back wide>
  <p class="braid-intro">Compose braid words from adjacent strand crossings. The diagram shows the braid, a simple closure, and the induced permutation.</p>

  <section class="braid-grid" id="braid-app">
    <article class="braid-card braid-controls">
      <label>strands <input id="braid-strands" type="number" min="2" max="8" value="4" /></label>
      <label>crossing <select id="braid-generator"></select></label>
      <button class="toolbar-button" id="braid-add-positive" type="button">add σ</button>
      <button class="toolbar-button" id="braid-add-negative" type="button">add σ⁻¹</button>
      <button class="toolbar-button" id="braid-reduce" type="button">reduce</button>
      <button class="toolbar-button" id="braid-clear" type="button">clear</button>
    </article>

    <article class="braid-card braid-wide">
      <div class="braid-head">
        <div>
          <h2>braid diagram</h2>
          <p id="braid-summary" class="braid-muted" aria-live="polite"></p>
        </div>
        <div id="braid-word" class="braid-word"></div>
      </div>
      <div class="braid-svg-wrap">
        <svg id="braid-plot" role="img" aria-label="Braid diagram"></svg>
      </div>
    </article>

    <article class="braid-card">
      <h2>permutation</h2>
      <div id="braid-permutation" class="braid-output"></div>
    </article>

    <article class="braid-card">
      <h2>closure sketch</h2>
      <div id="braid-closure" class="braid-output"></div>
    </article>
  </section>
</PageLayout>

<style>
  .braid-intro,
  .braid-muted,
  .braid-controls label,
  .braid-output,
  .braid-word { color: var(--muted); }

  .braid-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(min(100%, 22rem), 1fr)); gap: 1rem; }
  .braid-wide { grid-column: 1 / -1; }
  .braid-card { border: 1px solid var(--line); padding: 1rem; min-width: 0; }
  .braid-card h2 { font-size: 1rem; margin: 0 0 .5rem; }
  .braid-controls { display: flex; flex-wrap: wrap; align-items: end; gap: .75rem; }
  .braid-controls label { display: grid; gap: .25rem; }
  .braid-controls input[type="number"] { width: 4rem; padding: .25rem .4rem; }
  .braid-head { display: flex; justify-content: space-between; gap: 1rem; align-items: start; margin-bottom: 1rem; }
  .braid-word { max-width: 38rem; overflow-wrap: anywhere; font-variant-numeric: tabular-nums; text-align: right; }
  .braid-svg-wrap { border: 1px solid var(--line); background: var(--wash); overflow: auto; }
  #braid-plot { display: block; width: 100%; min-width: 38rem; height: 34rem; }
  .braid-output { display: grid; gap: .4rem; font-variant-numeric: tabular-nums; }
</style>

<style is:global>
  .braid-strand { fill: none; stroke: var(--fg); stroke-width: 4; stroke-linecap: round; }
  .braid-under { fill: none; stroke: var(--muted); stroke-width: 4; stroke-linecap: round; stroke-dasharray: 10 10; }
  .braid-guide { stroke: var(--line); stroke-width: 1; }
  .braid-label { fill: var(--muted); font: 12px ui-monospace, monospace; }
  .braid-chip { display: inline-block; border: 1px solid var(--line); border-radius: 999px; padding: .05rem .45rem; margin: .1rem; }
</style>

<script>
  import '../scripts/braid.ts';
</script>

